#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-28

# test-grader-determinism.sh — regression guard for #1545
#
# Asserts that CLAUDE_CODE_FORK_SUBAGENT=1 is exported by eval-common.sh and
# the workflow YAML. The actual end-to-end determinism (same input → same
# score across two runs) requires API access and runs in CI; this is the
# fast structural check that the wiring is in place.

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../../.." && pwd)}"
COMMON="$PROJECT_ROOT/tests/evals/scripts/lib/eval-common.sh"
WORKFLOW="$PROJECT_ROOT/.github/workflows/orchestkit-eval.yml"

PASS=0
FAIL=0

check() {
  local name="$1"; shift
  if "$@" >/dev/null 2>&1; then
    echo "  PASS $name"
    PASS=$((PASS + 1))
  else
    echo "  FAIL $name"
    FAIL=$((FAIL + 1))
  fi
}

echo "Grader determinism wiring tests (#1545)"
echo

echo "[eval-common.sh export]"
check "eval-common.sh exists"                       test -f "$COMMON"
check "exports CLAUDE_CODE_FORK_SUBAGENT"           grep -qE "^export CLAUDE_CODE_FORK_SUBAGENT" "$COMMON"
check "default value is 1"                          grep -qE 'CLAUDE_CODE_FORK_SUBAGENT.*:?-?1' "$COMMON"
check "respects user override"                      grep -qE 'CLAUDE_CODE_FORK_SUBAGENT:-1' "$COMMON"
check "links to issue #1545 in comment"             grep -q "#1545" "$COMMON"
echo

echo "[orchestkit-eval workflow env]"
check "workflow exists"                             test -f "$WORKFLOW"
check "workflow sets env CLAUDE_CODE_FORK_SUBAGENT" grep -qE "CLAUDE_CODE_FORK_SUBAGENT:\\s*1" "$WORKFLOW"
echo

echo "[runner scripts source eval-common]"
for runner in run-trigger-eval.sh run-quality-eval.sh run-agent-eval.sh optimize-description.sh; do
  f="$PROJECT_ROOT/tests/evals/scripts/$runner"
  check "$runner sources eval-common.sh"            grep -q "source.*eval-common" "$f"
done
echo

echo "[runtime sourcing test]"
# Source eval-common in a subshell and verify the env var is set.
ACTUAL=$(bash -c "source '$COMMON' >/dev/null 2>&1; echo \"\$CLAUDE_CODE_FORK_SUBAGENT\"")
if [[ "$ACTUAL" == "1" ]]; then
  echo "  PASS sourcing eval-common.sh exports CLAUDE_CODE_FORK_SUBAGENT=1"
  PASS=$((PASS + 1))
else
  echo "  FAIL sourcing eval-common.sh did not export CLAUDE_CODE_FORK_SUBAGENT (got: '$ACTUAL')"
  FAIL=$((FAIL + 1))
fi

# Also verify the override works
ACTUAL=$(CLAUDE_CODE_FORK_SUBAGENT=0 bash -c "source '$COMMON' >/dev/null 2>&1; echo \"\$CLAUDE_CODE_FORK_SUBAGENT\"")
if [[ "$ACTUAL" == "0" ]]; then
  echo "  PASS user override (CLAUDE_CODE_FORK_SUBAGENT=0) is respected"
  PASS=$((PASS + 1))
else
  echo "  FAIL user override not respected (got: '$ACTUAL')"
  FAIL=$((FAIL + 1))
fi
echo

echo "─── Results ───"
echo "  PASS: $PASS"
echo "  FAIL: $FAIL"
echo

if [[ $FAIL -gt 0 ]]; then exit 1; fi
exit 0
